void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = GetBlur3(vUv).y*vec3(roam_sin.z*1.4,0,0);
ret = mix(ret, -.4, GetBlur2(vUv).y);
